INSERT OR REPLACE INTO product_i18n (product_id, lang, name, category_label, description, sizes, specs) VALUES ('p1', 'ru', 'Садовый диван «Лагуна»', 'Садовая мебель', 'Садовая мебель из искусственного ротанга на лёгком алюминиевом каркасе. Плотное ручное плетение не выгорает на солнце, не боится дождя и перепадов температур — комплект круглый год может стоять на террасе, во дворе или в саду.', '["2-местный","3-местный","Угловой"]', '{"mat":"Искусственный ротанг + алюминий","dim":"С подушками, всесезонный","fin":"UV-стойкое плетение","wt":"Каркас алюминий","seat":"Терраса, двор, сад","made":"Ташкент, ручная работа"}');
INSERT OR REPLACE INTO product_i18n (product_id, lang, name, category_label, description, sizes, specs) VALUES ('p1', 'uz', '«Laguna» bog‘ divani', 'Bog‘ mebeli', 'Yengil alyumin karkasdagi sun’iy rotangdan bog‘ mebeli. Zich qo‘l to‘quvi quyoshda rangini yo‘qotmaydi, yomg‘ir va harorat o‘zgarishidan qo‘rqmaydi — to‘plam yil bo‘yi terassa, hovli yoki bog‘da turishi mumkin.', '["2 o‘rinli","3 o‘rinli","Burchak"]', '{"mat":"Sun’iy rotang + alyumin","dim":"Yostiqlar bilan, har faslga","fin":"UV-chidamli to‘quv","wt":"Alyumin karkas","seat":"Terassa, hovli, bog‘","made":"Toshkent, qo‘l mehnati"}');
INSERT OR REPLACE INTO product_i18n (product_id, lang, name, category_label, description, sizes, specs) VALUES ('p1', 'en', 'Laguna Garden Sofa', 'Garden furniture', 'Garden furniture in synthetic rattan over a light aluminium frame. The dense hand-weave won''t fade in the sun and shrugs off rain and temperature swings — the set can stay on the terrace, in the yard or garden all year round.', '["2-seater","3-seater","Corner"]', '{"mat":"Synthetic rattan + aluminium","dim":"With cushions, all-season","fin":"UV-stable weave","wt":"Aluminium frame","seat":"Terrace, yard, garden","made":"Tashkent, by hand"}');

