INSERT OR REPLACE INTO product_i18n (product_id, lang, name, category_label, description, sizes, specs) VALUES ('p3', 'uz', '«Kolonna» gultuvak', 'Gultuvak', 'Sun’iy rotangdan qo‘lda to‘qilgan gultuvak, yashirin ichki vkladish va drenaj bilan. Yengil, chirimaydi va yorilmaydi — uy, balkon va bog‘da jonli o‘simliklar bilan birdek chiroyli ko‘rinadi.', '["Ø30 sm","Ø40 sm","Ø55 sm"]', '{"mat":"Sun’iy rotang","dim":"Vkladish va drenaj bilan","fin":"Namlikka chidamli to‘quv","wt":"Yengil","seat":"Uy, balkon, bog‘","made":"Toshkent, qo‘l mehnati"}');
