INSERT OR REPLACE INTO product_i18n (product_id, lang, name, category_label, description, sizes, specs) VALUES ('p11', 'en', 'Linen Laundry Basket', 'Baskets & chests', 'A chest and laundry basket in synthetic rattan with a soft fabric liner and lid. Holds its shape, won''t snag fabric and stays ventilated — for laundry, throws, toys and bits in the bedroom or bathroom.', '["S","M","L"]', '{"mat":"Synthetic rattan + liner","dim":"With lid & liner","fin":"Smooth weave","wt":"Foldable liner","seat":"Laundry, throws, storage","made":"Tashkent, by hand"}');

