INSERT OR REPLACE INTO product_i18n (product_id, lang, name, category_label, description, sizes, specs) VALUES ('p12', 'ru', 'Кресло-качалка «Уют»', 'Мебель для дома', 'Мебель для дома из искусственного ротанга: лёгкая, тёплая на вид и практичная. Плетение не боится влаги и перепадов, легко протирается влажной тканью — под гостиную, спальню, прихожую или балкон.', '["Компакт","Стандарт","Большой"]', '{"mat":"Искусственный ротанг + каркас","dim":"Для интерьера, всесезонно","fin":"Гладкое плетение","wt":"Лёгкий каркас","seat":"Гостиная, спальня, балкон","made":"Ташкент, ручная работа"}');
INSERT OR REPLACE INTO product_i18n (product_id, lang, name, category_label, description, sizes, specs) VALUES ('p12', 'uz', '«Uyut» tebranma kreslo', 'Uy mebeli', 'Sun’iy rotangdan uy mebeli: yengil, ko‘rinishi issiq va amaliy. To‘quv namlik va o‘zgarishlardan qo‘rqmaydi, nam mato bilan oson artiladi — mehmonxona, yotoqxona, dahliz yoki balkon uchun.', '["Ixcham","Standart","Katta"]', '{"mat":"Sun’iy rotang + karkas","dim":"Interyer uchun, har faslga","fin":"Silliq to‘quv","wt":"Yengil karkas","seat":"Mehmonxona, yotoqxona, balkon","made":"Toshkent, qo‘l mehnati"}');
INSERT OR REPLACE INTO product_i18n (product_id, lang, name, category_label, description, sizes, specs) VALUES ('p12', 'en', 'Cosy Rocking Chair', 'Home furniture', 'Home furniture in synthetic rattan: light, warm-looking and practical. The weave shrugs off humidity and temperature swings and wipes clean with a damp cloth — right for the living room, bedroom, hallway or balcony.', '["Compact","Standard","Large"]', '{"mat":"Synthetic rattan + frame","dim":"For interiors, all-season","fin":"Smooth weave","wt":"Light frame","seat":"Living room, bedroom, balcony","made":"Tashkent, by hand"}');

